from collections import deque
class Solution:
    def makeStringsEqual(self, s, target):
        n = len(s)
        start = tuple(int(c) for c in s)
        goal = tuple(int(c) for c in target)
        if start == goal:
            return True
        seen = {start}
        dq = deque([start])
        while dq:
            cur = dq.popleft()
            for i in range(n):
                for j in range(n):
                    if i == j:
                        continue
                    a, b = cur[i], cur[j]
                    nxt = list(cur)
                    nxt[i] = a | b
                    nxt[j] = a ^ b
                    nxt = tuple(nxt)
                    if nxt == goal:
                        return True
                    if nxt not in seen:
                        seen.add(nxt)
                        dq.append(nxt)
        return False

